Entity* CommonAgent::getCurrentTargetEntity()
{
	NULL_RETURN(m_pCreature, nullptr);

	int currentTargetEntityId = m_pCreature->getCurrentTargetEntityId();
	if (currentTargetEntityId <= 0) {
		return nullptr;
	}

	Entity* entity = Server::Instance()->getWorld()->getEntity(currentTargetEntityId);
	return entity;
}

void CommonAgent::doRandomMove()
{
	//暂时屏蔽随机移动
	return;

	NULL_RETURN_VOID(m_pCreature);

	//移动中
	if (m_pCreature->hasPath())
	{
		return;
	}

	if (m_pCreature->getUpdatePathCd(m_pCreature->entityId) > 0) {
		return;
	}

	auto destPos = getRandomDestination();
	m_pCreature->getPathToPos(BlockPos(destPos.x, destPos.y, destPos.z));
	m_pCreature->setUpdatePathCd(m_pCreature->entityId);
	m_pCreature->changeCreatureAction(CREATURE_AS_MOVE);

	return;
}

Vector3 CommonAgent::getRandomDestination()
{
	NULL_RETURN(m_pCreature, Vector3());

	int radius = senseRange < 2 ? 2 : senseRange;
	auto birthPos = m_pCreature->getHomePosition();
	int destPosX = Math::IntervalRandom(birthPos.x - radius, birthPos.x + radius);
	int destPosZ = Math::IntervalRandom(birthPos.z - radius, birthPos.z + radius);

	return Vector3(destPosX, birthPos.y, destPosZ);
}
